
.tab-nav {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  padding: 8px 12px;
  background: rgba(0, 0, 0, 0.3);
  border-bottom: 1px solid rgba(100, 200, 255, 0.15);
}

.tab-btn {
  flex: 1;
  min-width: 70px;
  padding: 8px 12px;
  background: rgba(50, 50, 70, 0.5);
  border: 1px solid rgba(100, 200, 255, 0.2);
  border-radius: 6px;
  color: #a0a0a0;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s ease;

  &:hover {
    background: rgba(70, 70, 100, 0.6);
    color: #e0e0e0;
  }

  &.active {
    background: linear-gradient(180deg, rgba(50, 150, 200, 0.4) 0%, rgba(30, 100, 150, 0.3) 100%);
    border-color: rgba(100, 200, 255, 0.5);
    color: #64c8ff;
    box-shadow: 0 0 10px rgba(100, 200, 255, 0.2);
  }
}
