
.archive-panel {
  .section {
    margin-bottom: 16px;

    h3 {
      margin: 0 0 12px 0;
      font-size: 14px;
      color: #64c8ff;
      border-bottom: 1px solid rgba(100, 200, 255, 0.2);
      padding-bottom: 6px;
    }
  }

  .grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
  }

  .field {
    display: flex;
    flex-direction: column;
    gap: 4px;

    label {
      font-size: 11px;
      color: #a0a0a0;
    }

    input,
    select {
      padding: 6px 10px;
      background: rgba(40, 40, 55, 0.8);
      border: 1px solid rgba(100, 200, 255, 0.2);
      border-radius: 4px;
      color: #e0e0e0;
      font-size: 13px;

      &:focus {
        outline: none;
        border-color: rgba(100, 200, 255, 0.5);
      }
    }
  }
}
