
.combat-panel {
  .section {
    margin-bottom: 16px;

    h3 {
      margin: 0 0 12px 0;
      font-size: 14px;
      color: #64c8ff;
      border-bottom: 1px solid rgba(100, 200, 255, 0.2);
      padding-bottom: 6px;
    }
  }

  .grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
  }

  .field {
    display: flex;
    flex-direction: column;
    gap: 4px;

    label {
      font-size: 11px;
      color: #a0a0a0;
    }

    input,
    select {
      padding: 6px 10px;
      background: rgba(40, 40, 55, 0.8);
      border: 1px solid rgba(100, 200, 255, 0.2);
      border-radius: 4px;
      color: #e0e0e0;
      font-size: 13px;

      &:focus {
        outline: none;
        border-color: rgba(100, 200, 255, 0.5);
      }
    }

    .hint {
      font-size: 10px;
      color: #707080;
    }
  }

  .switch {
    position: relative;
    display: inline-block;
    width: 40px;
    height: 20px;

    input {
      opacity: 0;
      width: 0;
      height: 0;
    }

    .slider {
      position: absolute;
      cursor: pointer;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background-color: #3a3a4a;
      transition: 0.3s;
      border-radius: 20px;

      &:before {
        position: absolute;
        content: '';
        height: 14px;
        width: 14px;
        left: 3px;
        bottom: 3px;
        background-color: #a0a0a0;
        transition: 0.3s;
        border-radius: 50%;
      }
    }

    input:checked + .slider {
      background-color: rgba(100, 200, 255, 0.4);
    }

    input:checked + .slider:before {
      transform: translateX(20px);
      background-color: #64c8ff;
    }
  }
}
