
.warframe-status {
  width: 100%;
  max-width: 600px;
  background: linear-gradient(180deg, rgba(30, 30, 40, 0.95) 0%, rgba(20, 20, 30, 0.98) 100%);
  border: 2px solid rgba(100, 200, 255, 0.3);
  border-radius: 12px;
  box-shadow:
    0 4px 20px rgba(0, 0, 0, 0.5),
    0 0 30px rgba(100, 200, 255, 0.1);
  font-family: 'Microsoft YaHei', sans-serif;
  color: #e0e0e0;
  margin: 0 auto;
  overflow: hidden;
}

.header {
  background: linear-gradient(90deg, rgba(50, 150, 200, 0.3) 0%, rgba(100, 200, 255, 0.2) 100%);
  padding: 12px 16px;
  border-bottom: 1px solid rgba(100, 200, 255, 0.2);

  h2 {
    margin: 0;
    font-size: 18px;
    color: #64c8ff;
    text-shadow: 0 0 10px rgba(100, 200, 255, 0.5);
  }
}

.content-area {
  padding: 12px;
  min-height: 200px;
  max-height: 400px;
  overflow-y: auto;
}
