
.item-panel {
  .section {
    margin-bottom: 16px;

    h3 {
      margin: 0 0 12px 0;
      font-size: 14px;
      color: #64c8ff;
      border-bottom: 1px solid rgba(100, 200, 255, 0.2);
      padding-bottom: 6px;
    }
  }

  .grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
  }

  .field {
    display: flex;
    flex-direction: column;
    gap: 4px;

    label {
      font-size: 11px;
      color: #a0a0a0;
    }

    input {
      padding: 6px 10px;
      background: rgba(40, 40, 55, 0.8);
      border: 1px solid rgba(100, 200, 255, 0.2);
      border-radius: 4px;
      color: #e0e0e0;
      font-size: 13px;

      &:focus {
        outline: none;
        border-color: rgba(100, 200, 255, 0.5);
      }
    }
  }

  .items-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
    margin-bottom: 10px;
  }

  .item-card {
    background: rgba(40, 40, 55, 0.5);
    border: 1px solid rgba(100, 200, 255, 0.15);
    border-radius: 6px;
    padding: 10px;
  }

  .item-header {
    display: flex;
    gap: 8px;
    align-items: center;
    margin-bottom: 8px;

    input {
      flex: 1;
      padding: 6px 10px;
      background: rgba(40, 40, 55, 0.8);
      border: 1px solid rgba(100, 200, 255, 0.2);
      border-radius: 4px;
      color: #e0e0e0;
      font-size: 13px;
    }
  }

  .item-details {
    display: flex;
    flex-direction: column;
    gap: 6px;

    .field {
      input {
        width: 100%;
      }
    }
  }

  .btn-remove {
    width: 24px;
    height: 24px;
    background: rgba(255, 80, 80, 0.3);
    border: 1px solid rgba(255, 80, 80, 0.5);
    border-radius: 4px;
    color: #ff6060;
    cursor: pointer;
    font-size: 16px;
    line-height: 1;

    &:hover {
      background: rgba(255, 80, 80, 0.5);
    }
  }

  .btn-add {
    width: 100%;
    padding: 8px;
    background: rgba(100, 200, 255, 0.1);
    border: 1px dashed rgba(100, 200, 255, 0.3);
    border-radius: 4px;
    color: #64c8ff;
    cursor: pointer;
    font-size: 13px;

    &:hover {
      background: rgba(100, 200, 255, 0.2);
    }
  }
}
